function flipRecur(node, voyage, flipped, idx) {
    if (!node) return idx;
    if (node.val !== voyage[idx]) {
        flipped[0] = -1;
        return idx;
    }
    idx++;
    if (idx < voyage.length && node.left !== null && node.left.val !== voyage[idx]) {
        flipped.push(node.val);
        idx = flipRecur(node.right, voyage, flipped, idx);
        idx = flipRecur(node.left, voyage, flipped, idx);
    } else {
        idx = flipRecur(node.left, voyage, flipped, idx);
        idx = flipRecur(node.right, voyage, flipped, idx);
    }
    return idx;
}

function flipMatchVoyage(root, voyage) {
    let flipped = [];
    flipRecur(root, voyage, flipped, 0);
    if (flipped.length > 0 && flipped[0] === -1) return [-1];
    return flipped;
}
```


    1. Start with the root node and initialize an empty list `flipped`.
2. Create a recursive function `flipRecur` to traverse the tree, this function will have the following input parameters:
   - node: The current node in the tree.
   - voyage: The given voyage list.
   - idx: A counter to keep track of the position in the voyage list.
   - flipped: A reference to the list of flipped nodes.
3. If the current node is null (leaf node), return the idx.
4. Compare the current node value with the voyage list element at current idx:
   - If they don't match, set flipped list to [-1] and return the idx.
   - If they match, increment idx.
5. Check if the left subtree needs to be flipped by comparing the left child value with the next value in the voyage list.
   - If they don't match (the left subtree needs to be flipped), append the current node value to the flipped list and traverse the right subtree first, followed by the left subtree.
   - If they match, recursively traverse the left subtree, followed by the right subtree.

6. Call the `flipRecur` recursive function with the root node as the starting point.
7. If the first element of flipped list is -1, return [-1], otherwise, return the flipped list.

